  ('disabled-57f41407-moex-00401', 'disabled-57f41407', 'disabled-57f41407-moex-112-55d283b0', 'sub-disabled-57f41407-03', NULL, 'single_choice', '民法第184條第1項前段規定，因故意或過失，不法侵害他人權利者，負 損害賠償責任。甲駕駛汽車，將乙撞傷。認定甲之行為是否符合前述法律 規定之要件，而應負損害賠償責任的過程，稱為：', '["涵攝", "歸納", "證立", "類推"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:37+00:00", "source_pdf_sha1": "d2b7cdb0e0cd", "answer_pdf_sha1": "8efc4435d7d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0310", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
